import React, { useEffect, useState } from 'react';
import { getAllOrders, updateOrderStatus } from '../services/orderService';
import { Button, Badge } from '../components/atoms';
import './ChefDashboard.css';

export default function ChefDashboard() {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchOrders();
  }, []);

  const fetchOrders = async () => {
    try {
      setLoading(true);
      const data = await getAllOrders();
      const activeOrders = (data.data || data).filter(
        order => order.status !== 'Terminada' && order.status !== 'Cancelada'
      );
      setOrders(activeOrders);
    } catch (error) {
      console.error("Error fetching orders:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleStatusChange = async (orderId, currentStatus) => {
    let newStatus = '';
    if (currentStatus === 'Pendiente') newStatus = 'En preparación';
    else if (currentStatus === 'En preparación') newStatus = 'Terminada';

    if (newStatus) {
      try {
        await updateOrderStatus(orderId, newStatus);
        if (newStatus === 'Terminada') {
          setOrders(orders.filter(o => o._id !== orderId));
        } else {
          setOrders(orders.map(o => o._id === orderId ? { ...o, status: newStatus } : o));
        }
      } catch (error) {
        console.error("Error updating status:", error);
      }
    }
  };

  if (loading) return <div className="chef-dashboard"><p>Cargando órdenes...</p></div>;

  return (
    <div className="chef-dashboard">
      <div className="chef-header">
        <h1>Vista Chef - Órdenes Activas</h1>
        <Button variant="secondary" onClick={fetchOrders}>Actualizar</Button>
      </div>

      <div className="orders-grid">
        {orders.length === 0 ? (
          <p>No hay órdenes activas.</p>
        ) : (
          orders.map(order => (
            <div key={order._id} className="order-card">
              <div className="order-header">
                <h3>Orden #{order._id.substring(order._id.length - 6)}</h3>
                <Badge 
                  text={order.status} 
                  variant={order.status === 'Pendiente' ? 'warning' : 'primary'} 
                />
              </div>
              <div className="order-items">
                {order.items.map(item => (
                  <div key={item.product?._id || item._id} className="order-item-row">
                    <span>{item.quantity}x {item.product?.name || item.name}</span>
                  </div>
                ))}
              </div>
              <div className="order-actions">
                <Button 
                  variant="primary" 
                  onClick={() => handleStatusChange(order._id, order.status)}
                >
                  {order.status === 'Pendiente' ? 'Comenzar Preparación' : 'Marcar como Terminada'}
                </Button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
